targets.rawSql:
SELECT 'kline' AS dataset, COUNT(*) AS row_count, COUNT(*) - COUNT(DISTINCT close_time) AS duplicate_keys
FROM dashboard.futures_index_price_klines_${kline_interval}
WHERE $__timeFilter(close_time)
UNION ALL
SELECT 'futures_metrics' AS dataset, COUNT(*) AS row_count, COUNT(*) - COUNT(DISTINCT create_time) AS duplicate_keys
FROM dashboard.futures_metrics_${metrics_interval}
WHERE $__timeFilter(create_time)
UNION ALL
SELECT 'sentiment' AS dataset, COUNT(*) AS row_count, COUNT(*) - COUNT(DISTINCT create_time) AS duplicate_keys
FROM dashboard.sentiment_${sentiment_interval}
WHERE $__timeFilter(create_time)
UNION ALL
SELECT 'prediction' AS dataset, COUNT(*) AS row_count, COUNT(*) - COUNT(DISTINCT target_time) AS duplicate_keys
FROM dashboard.predictions_${kline_interval}
WHERE $__timeFilter(target_time)
  AND model_name = '${model_name}';
